#!/bin/bash
# Test Lumia claimAsset transactions against the proxy
#
# This script sends the 10 Lumia test vectors to the proxy's eth_sendRawTransaction
# endpoint and displays the results. These are real claimAsset calls from mainnet
# bridging LUMIA tokens to network 7 (Lumia L2).
#
# Usage:
#   ./scripts/test-lumia-claims.sh           # Test all 10 vectors
#   ./scripts/test-lumia-claims.sh 1         # Test only vector 1
#   ./scripts/test-lumia-claims.sh 1 3 5     # Test vectors 1, 3, and 5

set -e

PROXY_URL="${PROXY_URL:-http://localhost:8546}"

# Function to dump logs on error
# Saves both miden-node and miden-proxy logs to /tmp with matching timestamps
dump_logs_on_error() {
    local DT=$(date +%Y%m%d%H%M%S)
    local NODE_LOG="/tmp/miden-node-${DT}.log"
    local PROXY_LOG="/tmp/miden-proxy-${DT}.log"

    echo ""
    echo "Dumping logs to /tmp for debugging..."
    docker logs miden-miden-node-1 > "$NODE_LOG" 2>&1 || true
    docker logs miden-proxy-1 > "$PROXY_LOG" 2>&1 || true

    echo "  Node logs:  $NODE_LOG"
    echo "  Proxy logs: $PROXY_LOG"
}

# Test vectors from src/decode.rs - real Lumia claimAsset transactions
# All have: destination_network=7, origin_network=0, origin_token=LUMIA
#
# Expected amounts (verified from Lumia Blockscout explorer.lumia.org):
#   TX 1:  29,998 LUMIA      (29998000000000000000000 wei)
#   TX 2:  2 LUMIA           (2000000000000000000 wei)
#   TX 3:  2,500,007 LUMIA   (2500007000000000000000000 wei)
#   TX 4:  ~1.42 LUMIA       (1423553735952737020 wei)
#   TX 5:  ~2.31 LUMIA       (2308822999865217998 wei)
#   TX 6:  ~2.31 LUMIA       (2311627280562468739 wei)
#   TX 7:  ~0.996 LUMIA      (995904202009417401 wei)
#   TX 8:  315 LUMIA         (315000000000000000000 wei)
#   TX 9:  107.08 LUMIA      (107080000000000000000 wei)
#   TX 10: 69,184.51 LUMIA   (69184510000000000000000 wei)
#
declare -a TX_HASHES=(
    "0xe1a20811d757c48eba534f63041f58cd39eec762bfb6e4496dccf4e675fd5619"  # TX 1:  29998 LUMIA
    "0xe64254ff002b3d46b46af077fa24c6ef5b54d950759d70d6d9a693b1d36de188"  # TX 2:  2 LUMIA
    "0xd092dcf22398669262773cdd0e9749a5c01c75eab04f79d815566be041391c7c"  # TX 3:  2500007 LUMIA
    "0x73eb9910ff4cfdbd5d2bb77d1c020b82112765bfded64953131eaaef331f6c59"  # TX 4:  1.42 LUMIA
    "0x01a1886dc28a57d4d1b6e7f68e4f1fc35210276687942126b334ee636070c8df"  # TX 5:  2.31 LUMIA
    "0x6a2968ec482284787884319b702dab446cff6489bd27f63e1963cded33f6e253"  # TX 6:  2.31 LUMIA
    "0xb9f3c3f74be9d852d98da469db4a1bd21ee03e945301a129197bb65a19a24fca"  # TX 7:  0.996 LUMIA
    "0x5fbc96fe75987cc4579591b27d608ff0732b4572e392d23e04431b7c4f9b5c54"  # TX 8:  315 LUMIA
    "0xd3aa428a9bdc103bc3c65c47476e8262cc95fd246314af3f4e66f4fdf68eac32"  # TX 9:  107.08 LUMIA
    "0xefd30651db399351518b541b4e1371f01595b8c7b5beb073605f6825b20967d5"  # TX 10: 69184.51 LUMIA
)

# Expected amounts in wei (for validation)
declare -a EXPECTED_AMOUNTS_WEI=(
    "29998000000000000000000"    # TX 1
    "2000000000000000000"        # TX 2
    "2500007000000000000000000"  # TX 3
    "1423553735952737020"        # TX 4
    "2308822999865217998"        # TX 5
    "2311627280562468739"        # TX 6
    "995904202009417401"         # TX 7
    "315000000000000000000"      # TX 8
    "107080000000000000000"      # TX 9
    "69184510000000000000000"    # TX 10
)

declare -a TX_DATA=(
    # TX 1
    ""
    # TX 2
    ""
    # TX 3
    ""
    # TX 4
    ""
    # TX 5
    ""
    # TX 6
    ""
    # TX 7
    ""
    # TX 8
    ""
    # TX 9
    ""
    # TX 10
    ""
)

# Function to send a single test transaction
send_tx() {
    local idx=$1
    local tx_hash="${TX_HASHES[$idx]}"
    local tx_data="${TX_DATA[$idx]}"

    echo "========================================"
    echo "TX $((idx + 1)): $tx_hash"
    echo "========================================"
    echo "Sending claimAsset to $PROXY_URL..."
    echo ""

    # Build JSON-RPC request
    local request=$(cat <<EOF
{
    "jsonrpc": "2.0",
    "method": "eth_sendRawTransaction",
    "params": ["0x$tx_data"],
    "id": $((idx + 1))
}
EOF
)

    # Send request
    response=$(curl -s -X POST \
        -H "Content-Type: application/json" \
        -d "$request" \
        "$PROXY_URL")

    echo "Response:"
    echo "$response" | jq . 2>/dev/null || echo "$response"
    echo ""
}

# Pre-flight checks
preflight_check() {
    echo "============================================"
    echo "Pre-flight checks"
    echo "============================================"
    echo ""

    # Check 1: eth_chainId
    echo "1. Testing eth_chainId..."
    local chain_response=$(curl -sf -X POST \
        -H "Content-Type: application/json" \
        -d '{"jsonrpc":"2.0","method":"eth_chainId","params":[],"id":1}' \
        "$PROXY_URL" 2>&1)

    if [ $? -ne 0 ] || [ -z "$chain_response" ]; then
        echo "   FAILED: Proxy not responding at $PROXY_URL"
        echo "   Make sure the proxy is running: docker compose -f docker-compose.local.yml up -d"
        return 1
    fi

    local chain_id=$(echo "$chain_response" | jq -r '.result' 2>/dev/null)
    if [ "$chain_id" = "null" ] || [ -z "$chain_id" ]; then
        echo "   FAILED: Invalid response: $chain_response"
        return 1
    fi
    echo "   OK: Chain ID = $chain_id"

    # Check 2: eth_blockNumber
    echo "2. Testing eth_blockNumber..."
    local block_response=$(curl -sf -X POST \
        -H "Content-Type: application/json" \
        -d '{"jsonrpc":"2.0","method":"eth_blockNumber","params":[],"id":2}' \
        "$PROXY_URL" 2>&1)

    if [ $? -ne 0 ] || [ -z "$block_response" ]; then
        echo "   FAILED: eth_blockNumber not responding"
        return 1
    fi

    local block_num=$(echo "$block_response" | jq -r '.result' 2>/dev/null)
    if [ "$block_num" = "null" ] || [ -z "$block_num" ]; then
        echo "   FAILED: Invalid response: $block_response"
        return 1
    fi
    echo "   OK: Block number = $block_num"

    # Check 3: eth_gasPrice
    echo "3. Testing eth_gasPrice..."
    local gas_response=$(curl -sf -X POST \
        -H "Content-Type: application/json" \
        -d '{"jsonrpc":"2.0","method":"eth_gasPrice","params":[],"id":3}' \
        "$PROXY_URL" 2>&1)

    if [ $? -ne 0 ] || [ -z "$gas_response" ]; then
        echo "   FAILED: eth_gasPrice not responding"
        return 1
    fi

    local gas_price=$(echo "$gas_response" | jq -r '.result' 2>/dev/null)
    if [ "$gas_price" = "null" ] || [ -z "$gas_price" ]; then
        echo "   FAILED: Invalid response: $gas_response"
        return 1
    fi
    echo "   OK: Gas price = $gas_price"

    echo ""
    echo "All pre-flight checks passed!"
    echo ""
    return 0
}

# Main
echo "Lumia claimAsset Test Vectors"
echo "=============================="
echo "Proxy URL: $PROXY_URL"
echo ""

# Run pre-flight checks first
if ! preflight_check; then
    echo ""
    echo "Pre-flight checks FAILED. Aborting tests."
    echo "Please ensure the proxy is running and responding."
    dump_logs_on_error
    exit 1
fi

echo "Test vectors: 10 real Lumia bridge claims"
echo "  - destination_network: 7 (Lumia L2)"
echo "  - origin_network: 0 (Ethereum mainnet)"
echo "  - origin_token: 0xD9343a049D5DBd89CD19DC6BcA8c48fB3a0a42a7 (LUMIA)"
echo ""

# Check if specific indices were provided
if [ $# -gt 0 ]; then
    for arg in "$@"; do
        idx=$((arg - 1))
        if [ $idx -ge 0 ] && [ $idx -lt 10 ]; then
            send_tx $idx
        else
            echo "Invalid index: $arg (must be 1-10)"
        fi
    done
else
    # Run all 10 test vectors
    for i in {0..9}; do
        send_tx $i
    done
fi

echo "========================================"
echo "Done. Check proxy logs for decode output."
